// getWorkflowStaticData persists between runs — no external DB needed
const store = $getWorkflowStaticData('global');
if (!store.sessions) store.sessions = {};

const body = $input.first().json.body ?? $input.first().json;
const sessionId = body.session_id ?? 'default';

if (!store.sessions[sessionId]) store.sessions[sessionId] = [];

const turn = {
  transcript: body.transcript ?? '',
  action_taken: body.action_taken ?? null,
  result_summary: body.result_summary ?? null,
  timestamp: body.timestamp ?? new Date().toISOString()
};

// Keep last 20 turns per session
store.sessions[sessionId].push(turn);
if (store.sessions[sessionId].length > 20) {
  store.sessions[sessionId] = store.sessions[sessionId].slice(-20);
}

return [{ json: { success: true, session_id: sessionId, turn_count: store.sessions[sessionId].length } }];
